define i8 @add_shl_same_amount_constants(i8 %z) {
  %s1 = shl i8 4, %z
  %s2 = shl i8 3, %z
  %sum = add i8 %s1, %s2
  ret i8 %sum
}

define i6 @sub_shl_same_amount_partial_nuw2(i6 %x, i6 %y, i6 %z) {
  %xs = shl nuw i6 %x, %z
  %ys = shl i6 %y, %z
  %diff = sub nuw i6 %xs, %ys
  ret i6 %diff
}
